 &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#x2F;&amp;#x2F;单例定义方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   public function setPropertyErik($key,$val)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      $this-&amp;gt;props[$key]&amp;#x3D;$val;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   public function getPropertyErik($key)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      return $this-&amp;gt;props[$key];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   final protected function __clone()&amp;#123;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$perf&amp;#x3D;singleErik::getInstanceErik();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$perf-&amp;gt;setPropertyErik(&amp;quot;blog&amp;quot;,[&amp;quot;title&amp;quot;&amp;#x3D;&amp;gt;&amp;quot;艾瑞可erik&amp;quot;,&amp;quot;url&amp;quot;&amp;#x3D;&amp;gt;&amp;quot;https:&amp;#x2F;&amp;#x2F;erik.xyz&amp;quot;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$getData&amp;#x3D;$perf-&amp;gt;getPropertyErik(&amp;quot;blog&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print_r($getData);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;&amp;#x2F;销毁引用，释放空间&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unset($perf);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
