lass=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;81&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;82&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;83&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;84&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;85&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;86&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;87&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;89&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * 艾瑞可erik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * https:&amp;#x2F;&amp;#x2F;erik.xyz&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * Interface IStrategy&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * 策略模式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; *&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;interface IStrategyErik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    function filter($record);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class FindAfterStrategyErik implements IStrategyErik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private $_name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function __construct($name)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        $this-&amp;gt;_name &amp;#x3D; $name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load($name)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new FindAfterStrategyErik($name);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function filter($record)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return strcmp($this-&amp;gt;_name, $record) &amp;lt;&amp;#x3D; 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class RandomStrategyErik implements IStrategyErik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new RandomStrategyErik();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function filter($record)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return rand(0, 1) &amp;gt;&amp;#x3D; 0.5;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class UserListErik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private $_list &amp;#x3D; [];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load($arr &amp;#x3D; [])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new UserListErik($arr);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function __construct($names)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if ($names !&amp;#x3D; null) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            foreach ($names as $name) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                $this-&amp;gt;_list[] &amp;#x3D; $name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function add($name)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        $this-&amp;gt;_list[] &amp;#x3D; $name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function find($filter)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        $recs &amp;#x3D; [];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        foreach ($this-&amp;gt;_list as $user) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if ($filter-&amp;gt;filter($user)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                $recs[] &amp;#x3D; $user;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return $recs;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ul &amp;#x3D; UserListErik::load([&amp;quot;Andy&amp;quot;, &amp;quot;Jack&amp;quot;, &amp;quot;Lori&amp;quot;, &amp;quot;Megan&amp;quot;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$f1 &amp;#x3D; $ul-&amp;gt;find(FindAfterStrategyErik::load(&amp;quot;J&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print_r($f1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$f2 &amp;#x3D; $ul-&amp;gt;find(RandomStrategyErik::load());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print_r($f2);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;参考资料：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://www.ibm.com/developerworks/cn/opensource/os-php-designpatterns/?mhsrc=ibmsearch_a&amp;mhq=php%E8%AE%BE%E8%AE%A1%E6%A8%A1%E5%BC%8F&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;另外五个 PHP 设计模式&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://www.kancloud.cn/digest/php-src/136249&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;PHPer进阶&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;设置时区&lt;br&gt;date_default_timezone_set(“Asia/Shanghai”);&lt;br&gt;date_default_timezone_set(‘PRC’);//这两种方法效果相同&lt;br&gt;1&lt;br&gt;2&lt;br&gt;时间戳转日期，可以用date(‘Y-m-s h:i:s’, 具体时间戳来实现)&lt;br&gt;日期转换时间戳，用strtotime(“date()”).&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;时间戳格式&lt;br&gt;    //获取今日开始时间戳和结束时间戳&lt;br&gt;    $beginToday=mktime(0,0,0,date(‘m’),date(‘d’),date(‘Y’));&lt;br&gt;    $endToday=mktime(0,0,0,date(‘m’),date(‘d’)+1,date(‘Y’))-1;  &lt;/p&gt;
&lt;pre&gt;&lt;code&gt;//获取昨日起始时间戳和结束时间戳  
$beginYesterday=mktime(0,0,0,date(&amp;apos;m&amp;apos;),date(&amp;apos;d&amp;apos;)-1,date(&amp;apos;Y&amp;apos;));  
$endYesterday=mktime(0,0,0,date(&amp;apos;m&amp;apos;),date(&amp;apos;d&amp;apos;),date(&amp;apos;Y&amp;apos;))-1;  

//获取本周起始时间戳和结束时间戳   
$beginThisweek = mktime(0,0,0,date(&amp;apos;m&amp;apos;),date(&amp;apos;d&amp;apos;)-date(&amp;apos;w&amp;apos;)+1,date(&amp;apos;y&amp;apos;));  
$endThisweek=time();  

//获取上周起始时间戳和结束时间戳  
$beginLastweek=mktime(0,0,0,date(&amp;apos;m&amp;apos;),date(&amp;apos;d&amp;apos;)-date(&amp;apos;w&amp;apos;)+1-7,date(&amp;apos;Y&amp;apos;));  
$endLastweek=mktime(23,59,59,date(&amp;apos;m&amp;apos;),date(&amp;apos;d&amp;apos;)-date(&amp;apos;w&amp;apos;)+7-7,date(&amp;apos;Y&amp;apos;));  

//获取本月起始时间戳和结束时间戳  
$beginThismonth=mktime(0,0,0,date(&amp;apos;m&amp;apos;),1,date(&amp;apos;Y&amp;apos;));  
$endThismonth=mktime(23,59,59,date(&amp;apos;m&amp;apos;),date(&amp;apos;t&amp;apos;),date(&amp;apos;Y&amp;apos;));  

 //上个月的起始时间:  
$begin_time = strtotime(date(&amp;apos;Y-m-01 00:00:00&amp;apos;,strtotime(&amp;apos;-1 month&amp;apos;)));  
$end_time = strtotime(date(&amp;quot;Y-m-d 23:59:59&amp;quot;, strtotime(-date(&amp;apos;d&amp;apos;).&amp;apos;day&amp;apos;)));  

$begin_year = strtotime(date(&amp;quot;Y&amp;quot;,time()).&amp;quot;-1&amp;quot;.&amp;quot;-1&amp;quot;); //本年开始  
$end_year = strtotime(date(&amp;quot;Y&amp;quot;,time()).&amp;quot;-12&amp;quot;.&amp;quot;-31&amp;quot;); //本年结束  

//现在的时间到第二天凌晨相差的时间戳  
$time = (strtotime(date(&amp;apos;Y-m-d&amp;apos;))+3600*24) - time() ; &lt;/code&gt;&lt;/pre&gt;&lt;p&gt;日期格式&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#39;&amp;lt;br&amp;gt;上周起始时间:&amp;lt;br&amp;gt;&amp;#39;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+1-7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+7-7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#39;&amp;lt;br&amp;gt;本周起始时间:&amp;lt;br&amp;gt;&amp;#39;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#39;&amp;lt;br&amp;gt;上月起始时间:&amp;lt;br&amp;gt;&amp;#39;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;)-1,1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;) ,0,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#39;&amp;lt;br&amp;gt;本月起始时间:&amp;lt;br&amp;gt;&amp;#39;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;t&amp;quot;),date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;&amp;#x2F;本年起始&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(‘Y-01-01’); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;&amp;#x2F;结束日期 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(‘Y-12-31’);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;原文链接：&lt;a href=&#34;https://blog.csdn.net/qq_40018938/article/details/81031414&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://blog.csdn.net/qq_40018938/article/details/81031414&lt;/a&gt;&lt;/p&gt;

 &lt;h2 id=&#34;1&#34;&gt;&lt;a href=&#34;#1&#34; class=&#34;headerlink&#34; title=&#34;1&#34;&gt;&lt;/a&gt;1&lt;/h2&gt;&lt;p&gt;首先问大家两个问题：&lt;/p&gt;
&lt;p&gt;1）为什么爬树和种田最厉害的人，高考不能加分，而作文写得好的蒋方舟、打球打得好的科比和跨栏跑得快的刘翔，大学抢着要？&lt;/p&gt;
&lt;p&gt;2）为什么犹太人在历史上两千多年都受尽压迫，近现代却能牛人辈出？&lt;/p&gt;
&lt;p&gt;这两个问题不慌回答，看完全文，你自然明白。              &lt;/p&gt;
&lt;p&gt;现在我们先说本文的主旨：你之所以在城市里过得那么艰辛，成功离你那么遥不可及，可能是因为你还在用农业社会的思维和习惯去生活、工作、社交、投资，你没有适应工商业时代的社会需要。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;在城市里上过学，或已经在城市生活很久，甚至在城里长大，并不必然是个城里人了。只要从思维和行为习惯上，你还没有摆脱长期农业社会在你身上的烙印，你就还是一个乡下土人。&lt;/p&gt;
&lt;p&gt;你的土味，会杀死机遇，阻止成功，把你死死拖在失败的泥潭里。&lt;/p&gt;
&lt;p&gt;市场经济中，只有适应社会需要的人，才能赚到钱。不适应社会需要的，只能沦为屌丝。&lt;/p&gt;
&lt;p&gt;也就是说，只有去掉土味，你才可能成功。&lt;/p&gt;
&lt;h2 id=&#34;2&#34;&gt;&lt;a href=&#34;#2&#34; class=&#34;headerlink&#34; title=&#34;2&#34;&gt;&lt;/a&gt;2&lt;/h2&gt;&lt;p&gt;王小波的杂文《打工经历》里曾经说到过一件事。&lt;/p&gt;
&lt;p&gt;他在美国留学的时候，因为缺钱，和同学老曹揽了一个给中餐馆装修房子的活。那活本来轮不到他俩，因为老板特别抠门，舍不得请正规装修队，就让他俩来干。结果，俩人出尽了洋相。&lt;/p&gt;
&lt;p&gt;文章写得非常幽默。我把主要内容分享如下：&lt;/p&gt;
&lt;p&gt;“以前，我知道美国的科技发达、商业也发达，但我还不知道，美国还是各种手艺人的国家。我们打工的那条街上就有一大窝，什么电工、管子工、木工等等，还有包揽装修工程的小包工头儿；一听见我们开了工，就都跑来看。先看我们抡大锤、打钎子，面露微笑，然后就跑到后面去找老板，说：你请的这两个宝贝要是在本世纪内能把这餐馆装修完，我输你一百块钱。我脸上着实挂不住，真想扔了钎子不干。但老曹从牙缝里啐口吐沫说：不理他！这个世纪干不完，还有下个世纪，反正赤佬要给我们工钱……“&lt;/p&gt;
&lt;p&gt;王小波和老曹都没干过装修，就是卖力气。老曹提出要买各种工具，但抠门老板舍不得，认为他俩想揩油。&lt;/p&gt;
&lt;p&gt;“等把地面打掉以后，我们在这条街上赢得了一定程度的尊敬。顺便说一句，打下来的水泥块是我一块块抱出去，扔到垃圾箱里，老板连个手推车都舍不得租。他觉得已经出了人工钱，再租工具就是吃了亏。那些美国的工匠路过时，总来聊聊天，对我们的苦干精神深表钦佩。但是他们说，活可不是你们俩这种干法。说实在的，他们都想揽这个装修工程，只是价钱谈不拢。下一步是把旧有的隔断墙拆了。我觉得这很简单，挥起大锤就砸——才砸了一下，就被老板喝止。他说这会把墙里的木料砸坏。隔断墙里能有什么木料，不过是些零零碎碎的破烂木头。但老板说，要用它来造地板。于是，我们就一根根把这些烂木头上的钉子起出来。美国人见了问我们在干什么，我如实一说，对方捂住肚子往地下一蹲，笑得就地打起滚来。这回连老曹脸上都挂不住了，直怪我太多嘴……“&lt;/p&gt;
&lt;p&gt;后面，美国的工人都来围观他俩怎么干活。由于活实在太烂，对方好奇问他俩是干啥的。王小波之前是大学老师，老曹之前在沪东船厂当工程师，为了不给老东家丢脸，王小波厚着脸皮说两人都是艺术家。美国工人说：“早看出来你们是艺术家了……工人没有像你们这样干活的。“&lt;/p&gt;
&lt;p&gt;虽然又羞又愤，但因为是在是穷，他俩还是坚持下来。&lt;/p&gt;
&lt;p&gt;“我们给赤佬老板干了一个多月，也赚了他几百块钱的工钱，那个餐馆还是不像餐馆，也不像是冷库，而是像个破烂摊。转眼间夏去秋来，我们也该回去上学了。那老板的脸色越来越难看，天天催我们加班。催也没有用，手里拿着手锤铁棍，拼了命也是干不出活来的。“&lt;/p&gt;
&lt;p&gt;抠门老板实在是受不了了，直好把他俩开了，另请装修队。老曹倒很知耻，一定要弄清楚老美的工人是怎么干活的。&lt;/p&gt;
&lt;p&gt;“美国包工头接下了这个工程，马上把它分了出去，分给电工、木工、管子工，今天上午是你的，下午是他的，后天是我的，等等。几个电话打出去，就有人来送工具，满满当当一卡车。这些工具不要说我，连老曹都没见过。除了电锯电刨，居然还有用电瓶的铲车，可以在室内开动，三下五除二，就把我们留下的破烂从室内推了出去。电工上了电动升降台，在天花板上下电线，底下木工就在装配地板，手法纯熟之极。虽然是用现成的构件，也得承认人家干活真是太快了。装好以后电刨子一跑，贼亮；干完了马上走人，运走机械，新的工人和机械马上开进来……转眼之间，饭馆就有个样儿了……”&lt;/p&gt;
&lt;p&gt;最后王小波用下面这句话做了结尾：&lt;/p&gt;
&lt;p&gt;“我和老曹看了一会儿，就灰溜溜地走开了。这是因为我们都当过工人，知道怎么工作才有尊严。”&lt;/p&gt;
&lt;p&gt;我年轻时看这文，只知道挺好玩。后来才想明白，这其实是以小见大，深刻反映了两种文明的对撞和其中一种对另一种的绝对碾压。&lt;/p&gt;
&lt;p&gt;在该文里，王小波、老曹、抠门老板代表了农业文明下成长起来的，充满了乡土气息的乡下土人，美国工人代表了在现代工业文明下成长起来的现代人。在这次对撞中，农业文明被工业文明打击得体无完肤，毫无尊严——而这，又何尝不是工业革命以来，所有工业文明国家对农业文明国家全方位碾压的一个缩影。&lt;/p&gt;
&lt;h2 id=&#34;3&#34;&gt;&lt;a href=&#34;#3&#34; class=&#34;headerlink&#34; title=&#34;3&#34;&gt;&lt;/a&gt;3&lt;/h2&gt;&lt;p&gt;以色列学者尤瓦尔·赫拉利在他风靡全球的现象级畅销书《人类简史》中提出了一个观点，人类的生理结构和生活、思维、社交习惯，其实是为了适应数百万年的采集生活而形成的。这些习惯，到现在还在影响着我们。&lt;/p&gt;
&lt;p&gt;从这一推论出发，人类社会这几千年来不同的生活方式，也在不同的人群中形成了不同的思维和行为模式。80年代中国人曾经反思“黄土文明“，希望拥抱”海洋文明“。这种反思虽然后来走过了头，走向了对中华民族整个的否定，但其提出的一些观点是值得思考的。中国人的黄土思维，在现代化的冲击下，有些地方需要作出改变。&lt;/p&gt;
&lt;p&gt;托马斯·索威尔的名著《美国种族简史》分析了犹太人在现代社会的崛起。&lt;/p&gt;
&lt;p&gt;在长达2千年的时间里，犹太人是没有国家，没有土地的一个可怜的流浪民族。他们在任何一个地方，都处于被压榨、被排挤、被欺负、被诋毁、被防范的状态。由于长期没有土地，犹太人只好从事商业、手工业、中介、放贷收利息的古典金融业等行业。&lt;/p&gt;
&lt;p&gt;但是在工业革命之后，长期从事工商业的犹太人，迅速地适应了现代社会。不管是在欧洲还是新大陆，犹太人都飞速崛起，在商界、政界、知识界获得了举世瞩目的成绩。现代知名的世界级学者，很多是犹太人；金融业，犹太人掌控了华尔街，可以在全球呼风唤雨；律师、咨询等专业服务业，犹太人建立了非常好的口碑；在美国人中，犹太人占的比例只有2%，但哈佛的学生四分之一是犹太人；犹太人占全球人口比例约为0.3%，但是获得诺奖的比例却高达20%……&lt;/p&gt;
&lt;p&gt;但是，托马斯·索威尔特别提到，犹太人在很多行业都干得非常好，在农业领域就不行。美国的农业领域从没有出现过一家犹太农业巨头。&lt;/p&gt;
&lt;p&gt;别看现在以色列农业做得不错，那是工业化改造的农业。在欧洲和美国几百年的发展过程中，犹太人从来没有把农业做好过。因为，犹太人没有这方面的思维和行为习惯。换句网络流行语，就是犹太人没有搞农业的“种族天赋“。&lt;/p&gt;
&lt;p&gt;而中国人则不同。我们几千年来都是农业社会，已经达到了文明可以达到的巅峰。不管是生产力，还是文化，军事，政治，都创造了农业社会能达到的至高点。今天，中国人走到任何地方，第一件事就是把房前屋后的土地利用上，用来种菜。甚至，南海在大自然的鬼斧神工之下催生出了一批岛屿，我们的首要目的也是种上菜，“改善驻岛官兵的生活条件“。种菜，被认为是中国人的种族天赋。&lt;/p&gt;
&lt;p&gt;非常遗憾的是，现代社会，更需要工商业天赋，而不是种菜天赋。因此，中国人在工商业、金融业、政界、学界，暂时还竞争不过犹太人。因为我们还处于农业文明向工业文明的转型过程中。而犹太人，两千年来一致都是工商业文明。一遇到工业革命后的工业社会，就如鱼得水，迅速崛起。&lt;/p&gt;
&lt;h2 id=&#34;4&#34;&gt;&lt;a href=&#34;#4&#34; class=&#34;headerlink&#34; title=&#34;4&#34;&gt;&lt;/a&gt;4&lt;/h2&gt;&lt;p&gt;上面说的是从整体人群，或从文明/人种的角度而言，农业文明在现代社会的不适应性和工商业文明的适应性。其实，我们每一个人，拥有的是农业的乡土思维，还是工商业的现代思维，在社会上成功的概率有天壤之别。&lt;/p&gt;
&lt;p&gt;以下是我总结的乡土思维“七宗罪“。请对照一下，你有没有下面的毛病？这”七宗罪“，也许就是限制了你的发展空间，让你生活得那么艰难的原因。&lt;/p&gt;
&lt;p&gt;1）过于追求稳定，不敢冒风险&lt;/p&gt;
&lt;p&gt;我从体制内出来后，经常有朋友和我说，他们也想出来，可是不敢。也有很多非体制内的朋友，觉得现在的工作比较稳定，虽有种种不如意，且离自己的梦想十万八千里，但还是舍不得另起炉灶。这其实就是过于追求稳定的土味思维。&lt;/p&gt;
&lt;p&gt;农业社会最重视稳定，最害怕风险。儒家经典和史书记载里，中国人最喜欢的日子是风调雨顺，四时有序。因为农业生产必须稳定，有任何异常变动都可能造成颗粒无收。此外，自科举制以来，一千多年中国形成了根深蒂固的“学而优则仕”观念。一份稳定的工作，尤其是一个有保障的铁饭碗，在很多中国人心中成了最好的职业选择。&lt;/p&gt;
&lt;p&gt;西方社会主要是海洋文明，敢于冒风险，时刻都在处理不确定性。这种特质在农业社会没有太大用处。但是一旦进入工业时代，其威力就迅速发挥出来。文明特质与历史进程的匹配性，让西方国家超越了东方的中国、印度、奥斯曼，领先于世界。&lt;/p&gt;
&lt;p&gt;现代社会，时时刻刻都在发生变化，早已不是农业社会一辈子就守着几亩薄田，年复一年过同样日子的时候了。工商业社会，机遇是与风险成正比的。过于追求稳定，不能忍受不确定性，就会丧失很多机会。&lt;/p&gt;
&lt;p&gt;我们的父辈们更青睐体制内的工作，情有可原。因为他们大部分是农村出生、农村长大，或者刚刚洗脚上田。但是，80、90后的人，应该要学会拥抱不确定性，与不确定性共处。如果死抱着一份稳定的工作，或者被一个体制内职位束缚住，什么都不敢做，其实是乡土思维在限制你的未来。&lt;/p&gt;
&lt;p&gt;2）只混强关系圈，忽略弱关系&lt;/p&gt;
&lt;p&gt;亲戚、朋友、同学、老师、老乡，这些天然形成的，经常联系的关系，就是强关系。而从陌生开始建立联系，联系频率较少的关系，是弱关系。&lt;/p&gt;
&lt;p&gt;农业社会里，强关系是绝大部分人一辈子能接触的全部关系。儒家思想重要组成部分“礼”，其实就是弄明白每一个个体在强关系集合中所处的位置。费正清说，中国农村社会结构的核心就是家庭制度；而中国社会最重要的特点就是熟人社会。作为农业文明的巅峰，中国人的亲属关系可能是全世界分得最细致的，中文分出的叔叔、伯伯、舅舅、姨父、姑父等，英文里就一个uncle。&lt;/p&gt;
&lt;p&gt;而现代社会，更重要的可能是弱关系。因为，工商业时代的特征是市场主体发生交易，相互满足   ， 不是农业时代的自给自足或小范围交换的时代。因此，弱关系显得尤为重要。强关系由于交往的圈子相同，得到的外部信息太少，冗余信息太多。只有弱关系才能带来新鲜的、有价值的信息。&lt;/p&gt;
&lt;p&gt;所以，热衷于请客送礼，拉帮结派，建立和维护强关系纽带的思维将越来越落后于时代，而以信息和价值交换为主的弱关系思维，才更适合于当今的工商业时代需求。&lt;/p&gt;
&lt;p&gt;关于弱关系的价值，可参考《拼多多上市，80后创始人28个月做到身家800亿，凭的就是弱关系》（此文120万+阅读，影响了无数人）、《 人生最好的机会，往往来自弱关系》两篇文章。&lt;/p&gt;
&lt;p&gt;3）相信宿命论，而不是个人奋斗&lt;/p&gt;
&lt;p&gt;我们常常听人说，“这都是命”，“我哪有这么好的命”，“努力了也没用，结果还是一样”等。这些，其实都是土味思维。&lt;/p&gt;
&lt;p&gt;农业社会生产力落后，人的力量有限而自然的力量无穷，人们特别容易想象自己的一切都由老天决定。从社会形态来说，农业社会又太过凝固不变，一个人无论如何拼命奋斗，基本上没有可能改变自己的命运，由此形成了强烈的宿命论观点。即便是战乱时刻出来几个乱世英雄，或者科举中出来几个苦读成才的高官，也往往被人们认为是前世积德或文曲星下凡之类。&lt;/p&gt;
&lt;p&gt;中国的农民非常勤奋，但这种勤奋是为了活命而不得不干苦力的勤奋，而不是相信自己的勤奋能改变命运。只有读书人可以说通过寒窗苦读，走科举之路来逆天改命，但比例太少了，和99%的农民没有关系。&lt;/p&gt;
&lt;p&gt;西方社会自大航海时代以来，就有无数的个人通过努力奋斗改变了自己和家庭的命运，这种现象的普遍性，让西方社会形成了通过个人努力可以实现梦想的普遍预期，“美国梦”就是其具体体现。&lt;/p&gt;
&lt;p&gt;工商业时代，竞争永无休止，个人一定不能服输认命。你一停止奋斗，社会就把你抛在后头，阶层就把你踩在底下。个人奋斗，是让自己生活过得更好的必由之路。如果你认命，或者期望通过中彩票这样的运气来改善生活，那你必然会越过越艰难，越来越失望。&lt;/p&gt;
&lt;p&gt;4）喜欢屯东西，在不必要的地方拼命省钱&lt;/p&gt;
&lt;p&gt;每个家庭都有这么一位老人，什么东西都屯着，永远舍不得扔。家里都快站不下脚了，瓶瓶罐罐破铜烂铁摆得满屋都是，你要当垃圾扔掉，还得说你不会过日子。&lt;/p&gt;
&lt;p&gt;每个家庭也还有这么一位老人，宁愿早高峰挤一个小时公交车去大菜场买菜，也不愿意在楼下的菜店买，因为大菜场便宜几毛钱。吃剩的饭菜，一定舍不得扔掉，要么不顾自己早已经“三高”，硬撑着非要吃完，要么留到下一顿，下下顿，接着吃已经产生了无数有害于身体的亚硝酸盐的剩菜。&lt;/p&gt;
&lt;p&gt;这些，都是长期农业社会物质极度缺乏留下的后遗症。&lt;/p&gt;
&lt;p&gt;我们都知道，美国人喜欢搬家，一辆车就把所有东西装走，穿州过省，换个地方生活。而中国人，搬一次家，简直要了老命。这其中的区别，就在于美国人家里屯的不必要东西少，搬起来容易。去过外国人家里参观的，会发现非常简单整洁，空间感很好。而中国人的房子，无论多大，总是不够放东西。为什么北欧装修是极简风？因为北欧人已经习惯了工业化时代的生活，不要的东西就扔掉，需要的时候再买就是。&lt;/p&gt;
&lt;p&gt;在不必要的地方省钱，更是要命的毛病。有人总喜欢买最便宜的水果、面包，味道不好不说，还经常是烂的或快过期的，结果既没满足口腹之欲，又有害于身体。在工作上，有人喜欢买低配的电脑或手机，盗版的软件，结果用得处处不爽，每天心情都受影响，很多时候还耽误了工作。&lt;/p&gt;
&lt;p&gt;工商业社会，需要重视空间的价值，重视体验的价值，重视时间的价值。不要把农业社会的土味思维带进来，让自己活得憋屈难受，工作得不爽或低效。&lt;/p&gt;
&lt;p&gt;5）抱着复古心态，而不是拥抱未来&lt;/p&gt;
&lt;p&gt;前不久，当代最顶尖的数学家迈克尔·阿蒂亚宣称证明了“黎曼猜想”。后来大家发现，这位数学家原来是老糊涂了（有兴趣的朋友可参阅我的文章《 满屏的“黎曼猜想”，到底在讲些什么？》）。我想，还好这是现代，我们不会盲目接受老人，尤其是曾经很牛的老人的一切教导（中国在这方面吃过的亏还小吗？）。而在中国古代，人们总是认为，古人比今人厉害，老人比年轻人厉害，古代比现在厉害。&lt;/p&gt;
&lt;p&gt;农业社会的发展是平的，一千年过去，社会还是一个样子，人们的生活也还是一个样子。在这样的社会里，古人和老人的经验总是适用的。而由于社会没有变化，未来是无望的，人们就把美好希望都寄托在过去。中国文人爱幻想“上古时期”、“三王之治”，认为那是人类的黄金时代。&lt;/p&gt;
&lt;p&gt;直到工业革命后，人类才习惯于明天的生活会比今天更好，下一代的生活会比这一代更好。而中国人过上这样的日子，也才几十年。我们还没有能够把这种思维融入到骨子里。我们还会认为，学问是古人的高，药方是古人的好，认为自己人生所能达到的巅峰就是现在，不敢放弃现在去搏一个更好的未来。&lt;/p&gt;
&lt;p&gt;工商业时代，我们必须抛弃这种土味思维。我们要向年轻人学习，年轻人掌握新的技术、新的潮流，比我们厉害多了；我们要着眼未来，要相信凭自己的双手，能创造更好的未来。只有这样，才能跟上风口，跟上时代的步伐。&lt;/p&gt;
&lt;p&gt;6）平均主义思维&lt;/p&gt;
&lt;p&gt;在咨询工作中，我常常需要在各个企业访谈。我发现，在关于薪酬待遇的访谈中，不管是高管，还是中层，还是普通员工，每个人都觉得自己拿得少，而别人拿得多，说的最多的意见是，希望薪酬政策能体现“公平公正”。但也有少数人会说，希望薪酬政策能体现价值贡献，贡献大的多拿，贡献小的少拿。&lt;/p&gt;
&lt;p&gt;前一种思维，就是土味思维；后一种，才是现代思维。&lt;/p&gt;
&lt;p&gt;中国古代的继承制度是“诸子均分“制。家庭财产，会在各个儿子之间平分。只有皇位/爵位或名位等，采取嫡长子继承制，但是其他儿子也有会有相应的权利。&lt;/p&gt;
&lt;p&gt;而西方社会古代多采用“长子继承”制，爵位或全部家庭财产都由长子继承，其他儿子自谋出路去。&lt;/p&gt;
&lt;p&gt;由此产生的思维习惯是，中国人特别喜欢平均主义，圣人总结为“不患寡而患不均”。凡是要革命，一定要喊“均田地”、“均贫富”、“平均地权”等口号。&lt;/p&gt;
&lt;p&gt;在财富线性积累的农业时代，平均主义容易实现，也有其道理。但是在财富指数化增涨的工商业时代，这种思维就大大落后了。现代社会的财富分配，遵从着幂律分布，通俗来讲，80%的新增财富，会被20%的人拿到。一家公司80%的奖金，会被20%的人瓜分。现代社会，已经不可能再有平均主义。如果一个国家有平均主义，那就是大锅饭式的灾难再次重临。如果一个企业有平均主义，那就离倒闭不远了。&lt;/p&gt;
&lt;p&gt;如果你还抱着平均主义思维，你永远只会抱怨不公，每天负能量满满，牢骚满腹。不如抛弃平均主义土味思维，认清社会现实，多想想自己怎么进入那20%中去吧。&lt;/p&gt;
&lt;p&gt;7）时间观念的淡漠&lt;/p&gt;
&lt;p&gt;有一位特别优秀的求职者，希望来我公司就职。我看其简历无可挑剔，视频面试也感觉不错，于是约了合伙人一起面试。结果30分钟的面试时间，小伙子迟到了10分钟。合伙人坚决要求不招，我也只好把他遗憾劝退。&lt;/p&gt;
&lt;p&gt;守时，是现代工商业社会的基本素质之一。不守时，本质上是一种土味思维和习惯。&lt;/p&gt;
&lt;p&gt;农业社会的时间观念是“农时”，节气最重要，只要不误了节气，就不会误了农作。而农闲的时候，时间就完全失去了意义。所以，农业社会的人，对时间的精准性要求不高。&lt;/p&gt;
&lt;p&gt;当然，农业社会比热带地区好一点。热带地区的人们以采摘和捕猎维生，以季节来计算时间。什么季节去什么地方，就能吃到香蕉，或者逮到角马，这个时间的精准度就更差。所以我们可以看到，再不守时的中国人，到了非洲、印度、拉美，也简直要被当地人的不守时给气死。&lt;/p&gt;
&lt;p&gt;工商业社会就不同，货物的交割要精确到天，交通运输要精确到分，生产线上的操作要精确到秒，如果没有时间观念，很容易乱套。我们看到，发展得比较好的工业国家，德国、英国、北欧，都是极其守时的，而南欧就差一些，所以西班牙、葡萄牙、希腊经济就不行（当然还是好过农业国家）。&lt;/p&gt;
&lt;p&gt;前面说的是对他人时间的不尊重。另一个更要命的土味思维，是对自己的时间不尊重。&lt;/p&gt;
&lt;p&gt;一是使用低效率的工具或方式去做事。上面王小波的文章里写到的就是典型。现实生活中也有很多，明明买得起3小时到达的高铁票，非要买12小时到达的普票；明明打的10分钟可到，非要坐公交摇晃1小时；明明正版软件一分钟就能解决的事，非要用盗版软件花三个小时去完成；明明充个会员就能直接看剧，非要为了免费先看75秒广告……时间都被这些低效的东西给浪费了。&lt;/p&gt;
&lt;p&gt;二是把过多的时间花费在无益的事情上面。别人在学习，你在打游戏。别人在工作，你在刷抖音。游戏抖音5分钟，人间已过3小时，可你还乐此不疲。&lt;/p&gt;
&lt;p&gt;你有没有想过：你的时间价值，决定了你的工资。你认为你一个小时值多少钱，就是你能拿到的工资的最高点。如果你自己都认为自己的时间不值钱，你的工资怎么可能高得了呢？ &lt;/p&gt;
&lt;h2 id=&#34;5&#34;&gt;&lt;a href=&#34;#5&#34; class=&#34;headerlink&#34; title=&#34;5&#34;&gt;&lt;/a&gt;5&lt;/h2&gt;&lt;p&gt;我们必须得认识到，现代世界是工商业的世界，只有符合新时代需求的事情，才能产生价值；只有做出符合新时代需求的事情的人，才能赚到钱。土味思维，只会限制你，使你远离成功。&lt;/p&gt;
&lt;p&gt;以下是几点如何适应工商业时代的建议。&lt;/p&gt;
&lt;p&gt;1）研究工商业社会的需求&lt;/p&gt;
&lt;p&gt;工商业社会的需求和农业社会的需求是不同的。爬树、种田，是农业社会的需求；文学、体育、娱乐等是工商业社会的需求。这就是为什么爬树、种田不能加分，而蒋方舟、科比和刘翔被大学抢着要的原因。&lt;/p&gt;
&lt;p&gt;我们要从社会需求出发，而不是个人能力出发，去看待问题。&lt;/p&gt;
&lt;p&gt;你说你锯木头特别快、或者剪纸特别好、或者化妆术超越天龙八部里面的阿朱，对市场而言，这都没有意义。&lt;/p&gt;
&lt;p&gt;只有有人闲得无聊喜欢看人锯木头，有些追求高品质小众娱乐的人就是想学剪纸，有些希望展现更完美自我的女生就是喜欢学化妆，而且你能找到这些人，把自己推送给这些人，你的能力才有用武之地。&lt;/p&gt;
&lt;p&gt;所以，我们首先要学会去研究工商业社会的需求。这些需求还有很多很多，你能满足其中哪怕很小的一点，都能赚到很多的钱。&lt;/p&gt;
&lt;p&gt;2）培养适合工商业社会的思维&lt;/p&gt;
&lt;p&gt;首先是前面提到的土味思维“七宗罪”要坚决摈弃。&lt;/p&gt;
&lt;p&gt;除此外，你还要养成不靠关系，靠市场规则和个人奋斗的习惯；要终生学习，不懈努力，始终向上生长；要有长远眼光和投资思维，学会利用复利的力量；要注意树立个人品牌（弱关系社会，个人品牌无比重要）。&lt;/p&gt;
&lt;p&gt;这里的每一点，都值得写一篇5千字长文去阐述。只要你持续关注何加盐公众号，以后都能学到。&lt;/p&gt;
&lt;p&gt;3）锻炼工商业社会的生存发展能力&lt;/p&gt;
&lt;p&gt;我把这条放在最后，是因为从逻辑上，你先要知道市场有哪些需求，你应该具备哪些底层思维，然后再来锻炼相关的能力。只有这样，才能有的放矢，事半功倍，不至于走弯路。&lt;/p&gt;
&lt;p&gt;你要培养的能力，是从需求而来的，是在你的底层思维的帮助下培养和发挥的。至于具体什么能力，要看你对市场需求的把握程度和你的兴趣爱好特长而定。&lt;/p&gt;
&lt;p&gt;我可以举一些例子供你参考，但你自已也要思考和寻找：&lt;/p&gt;
&lt;p&gt;例如：如何帮助生产者提高效率、降低成本（相关的专业和技能：人工智能、机械制造、工程设计、信息化、管理学、会计学等等），如何帮助卖方迅速找到买方（相关的专业和技能：营销、电子商务、大数据、广告设计、市场策划等等），如何取悦后工业社会娱乐至上的民众（相关专业和技能：文学、艺术、体育等等，但是必须能达到高水平）等等。&lt;/p&gt;
&lt;p&gt;还有一些通用的必备能力，例如：理财能力（你需要学习理财知识），运动能力（你需要锻炼身体），统计分析能力（你需要具备一些基本的统计学知识），领导能力（你需要学习怎么驱动自己和他人），语言能力（你需要学会如何演讲，或者学一门或几门外语），写作能力（你需要经常动笔写东西）等等。总之，工商业社会需要什么，你就锻炼什么。只要自己有能力，不愁抓不住机会。&lt;/p&gt;
&lt;h2 id=&#34;6&#34;&gt;&lt;a href=&#34;#6&#34; class=&#34;headerlink&#34; title=&#34;6&#34;&gt;&lt;/a&gt;6&lt;/h2&gt;&lt;p&gt;中国农业社会持续了几千年，进入工商业社会，还没有多长时间。我们每一个人，或多或少都具有一些乡土味，这跟你在城市长大还是农村长大没有关系，而是来自于我们的历史传承，深埋在我们的骨髓里面。&lt;/p&gt;
&lt;p&gt;乡土味或现代味，并没有高低之分，但是有不同的适用环境。在工商业社会，乡土思维，会限制你成功，而现代思维，会帮助你发展。&lt;/p&gt;
&lt;p&gt;换句话说，你有多土，就会有多穷。洗掉土味，才能走向成功。&lt;/p&gt;
&lt;p&gt;作者简介：何加盐，一个专门研究牛人的牛人。曾在政府工作，后创立咨询公司，现为咨询顾问，公众号写手。和你一起了解牛人是怎么炼成的，从牛人的经历与方法中，获得思维与认知的提升。了解牛人，学习牛人，成为牛人，从关注何加盐开始&lt;/p&gt;
&lt;p&gt;本文转载地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/783yvYbdVoDjTTe-EgEbOw&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/783yvYbdVoDjTTe-EgEbOw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;作者：回首笑人间，高级Java工程师一枚，热爱研究开源技术，架构师社区合伙人！&lt;br&gt;目录&lt;/p&gt;
&lt;p&gt;什么是持续集成&lt;br&gt;Jenkins简介&lt;br&gt;Jenkins安装与启动&lt;br&gt;Jenkins插件安装&lt;br&gt;全局工具配置&lt;br&gt;自动安装&lt;br&gt;本地安装&lt;br&gt;代码上传至Git服务器&lt;br&gt;任务的创建与执行&lt;br&gt;Go项目&lt;br&gt;JAVA项目&lt;br&gt;什么是持续集成&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;br&gt;持续集成 Continuous integration ，简称CI&lt;/p&gt;
&lt;p&gt;随着软件开发复杂度的不断提高，团队开发成员间如何更好地协同工作以确保软件开发的质量已经慢慢成为开发过程中不可回避的问题。尤其是近些年来，敏捷（Agile） 在软件工程领域越来越红火，如何能在不断变化的需求中快速适应和保证软件的质量也显得尤其的重要。&lt;/p&gt;
&lt;p&gt;持续集成正是针对这一类问题的一种软件开发实践。它倡导团队开发成员必须经常集成他们的工作，甚至每天都可能发生多次集成。而每次的集成都是通过自动化的构建来验证，包括自动编译、发布和测试，从而尽快地发现集成错误，让团队能够更快的开发内聚的软件。&lt;/p&gt;
&lt;p&gt;持续集成具有的特点：&lt;/p&gt;
&lt;p&gt;它是一个自动化的周期性的集成测试过程，从检出代码、编译构建、运行测试、结果记录、测试统计等都是自动完成的，无需人工干预；&lt;br&gt;需要有专门的集成服务器来执行集成构建；&lt;br&gt;需要有代码托管工具支持，例如Git以及可视化界面Gogs的使用&lt;br&gt;持续集成的作用：&lt;/p&gt;
&lt;p&gt;保证团队开发人员提交代码的质量，减轻了软件发布时的压力；&lt;br&gt;持续集成中的任何一个环节都是自动完成的，无需太多的人工干预，有利于减少重复过程以节省时间、费用和工作量；&lt;br&gt;Jenkins简介&lt;br&gt;Jenkins，原名Hudson，2011年改为现在的名字，它 是一个开源的实现持续集成的软件工具。官方网站：&lt;a href=&#34;http://jenkins-ci.org/。&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;http://jenkins-ci.org/。&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Jenkins 能实施监控集成中存在的错误，提供详细的日志文件和提醒功能，还能用图表的形式形象地展示项目构建的趋势和稳定性。&lt;/p&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;p&gt;易安装：仅仅两个docker命令即可从官网下载直接运行，无需额外的安装，更无需安装数据库；&lt;br&gt;易配置：提供友好的GUI配置界面；&lt;br&gt;变更支持：Jenkins能从代码仓库（Subversion/CVS）中获取并产生代码更新列表并输出到编译输出信息中；&lt;br&gt;支持永久链接：用户是通过web来访问Jenkins的，而这些web页面的链接地址都是永久链接地址，因此，你可以在各种文档中直接使用该链接；&lt;br&gt;集成E-Mail/RSS/IM：当完成一次集成时，可通过这些工具实时告诉你集成结果（据我所知，构建一次集成需要花费一定时间，有了这个功能，你就可以在等待结果过程中，干别的事情）；&lt;br&gt;JUnit/TestNG测试报告：也就是用以图表等形式提供详细的测试报表功能；&lt;br&gt;支持分布式构建：Jenkins可以把集成构建等工作分发到多台计算机中完成；&lt;br&gt;文件指纹信息：Jenkins会保存哪次集成构建产生了哪些jars文件，哪一次集成构建使用了哪个版本的jars文件等构建记录；&lt;br&gt;支持第三方插件：使得 Jenkins 变得越来越强大&lt;br&gt;Jenkins安装与启动&lt;br&gt;（1）执行安装命令,下载jenkins&lt;/p&gt;
&lt;p&gt;docker pull jenkins/jenkins&lt;br&gt;（2）启动服务&lt;/p&gt;
&lt;p&gt;docker run -p 8080:8080 -p 50000:50000 -v /mnt/data/jenkins:/var/jenkins_home –name “jenkins” jenkins/jenkins&lt;/p&gt;
&lt;p&gt;若报错如下:&lt;/p&gt;
&lt;p&gt;touch: cannot touch ‘/var/jenkins_home/copy_reference_file.log’: Permission denied&lt;br&gt;Can not write to /var/jenkins_home/copy_reference_file.log. Wrong volume permissions?&lt;br&gt;需要修改下目录权限, 因为当映射本地数据卷时，/mnt/data/jenkins目录的拥有者为root用户，而容器中jenkins user的uid为1000&lt;/p&gt;
&lt;p&gt;sudo chown -R 1000:1000 /mnt/data/jenkins&lt;br&gt;（3）访问链接 &lt;a href=&#34;http://10.20.29.151:8080&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;http://10.20.29.151:8080&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;若密码忘记，可进入容器，执行cat /var/lib/jenkins/secrets/initialAdminPassword获取初始密码串。&lt;br&gt;若目录不存在，可使用find / -name “initialAdminPassword” -depth -print命令查找。&lt;/p&gt;
&lt;p&gt;（4）安装插件&lt;/p&gt;
&lt;p&gt;（5）新建用户&lt;/p&gt;
&lt;p&gt;完成安装进入主界面&lt;/p&gt;
&lt;p&gt;Jenkins插件安装&lt;br&gt;我们以安装maven插件为例，演示插件的安装&lt;/p&gt;
&lt;p&gt;（1）点击左侧的“系统管理”菜单 ,然后点击&lt;/p&gt;
&lt;p&gt;（2）选择“可选插件”选项卡，搜索maven，在列表中选择Maven Integration ，点击“直接安装”按钮&lt;/p&gt;
&lt;p&gt;看到如下图时，表示已经完成&lt;/p&gt;
&lt;p&gt;注:如果你的项目是GitHub、GitLib或是Go语言等项目，那么我想你都需要这么一个对应的插件来帮你干活。&lt;br&gt;全局工具配置&lt;br&gt;选择系统管理，全局工具配置&lt;/p&gt;
&lt;p&gt;自动安装&lt;/p&gt;
&lt;p&gt;Jenkins提供了两种工具配置的方式，我们还是以maven为例&lt;/p&gt;
&lt;p&gt;第一种如上图，只需要选择自动安装和版本号就可以，同时Jenkins在右上角给出了一个解疑按键，可以通过该键看到说明和示例。&lt;/p&gt;
&lt;p&gt;本地安装&lt;/p&gt;
&lt;p&gt;相较于第一种方式，第二种方式相对麻烦一些，但好处是可以在以后打包的时候不必重新下载，缩短打包的时间。&lt;/p&gt;
&lt;p&gt;下面就来教大家如何安装Maven与本地仓库：&lt;/p&gt;
&lt;p&gt;（1）将Maven压缩包上传至服务器（虚拟机）&lt;/p&gt;
&lt;p&gt;（2）解压&lt;/p&gt;
&lt;p&gt;tar zxvf apache-maven-3.5.4-bin.tar.gz&lt;br&gt;（3）移动目录&lt;/p&gt;
&lt;p&gt;mv apache-maven-3.5.4 /usr/local/maven&lt;br&gt;（4）编辑setting.xml配置文件vi /usr/local/maven/conf/settings.xml，配置本地仓库目录,内容如下&lt;/p&gt;
&lt;p&gt;&lt;localRepository&gt;/usr/local/repository&lt;/localRepository&gt;&lt;br&gt;（5）将开发环境的本地仓库上传至服务器（虚拟机）并移动到/usr/local/repository 。&lt;/p&gt;
&lt;p&gt;mv reponsitory_boot /usr/local/repository&lt;br&gt;其他示例:&lt;/p&gt;
&lt;p&gt;（1）JDK配置&lt;/p&gt;
&lt;p&gt;设置javahome为 /usr/java/jdk1.8.0_171-amd64&lt;/p&gt;
&lt;p&gt;（2）Git配置 （本地已经安装了Git软件）&lt;/p&gt;
&lt;p&gt;（3）Maven配置&lt;/p&gt;
&lt;p&gt;代码上传至Git服务器&lt;br&gt;步骤：&lt;/p&gt;
&lt;p&gt;（1）在本地安装git(Windows版本)&lt;/p&gt;
&lt;p&gt;（2）在IDEA中选择菜单 : File – settings , 在窗口中选择Version Control – Git&lt;/p&gt;
&lt;p&gt;（3）选择菜单VCS –&amp;gt; Enable Version Control Integration…&lt;/p&gt;
&lt;p&gt;选择Git&lt;/p&gt;
&lt;p&gt;（4）设置远程地址: 右键点击工程选择菜单 Git –&amp;gt; Repository –&amp;gt;Remotes…&lt;/p&gt;
&lt;p&gt;（5）右键点击工程选择菜单 Git –&amp;gt; Add&lt;/p&gt;
&lt;p&gt;（6）右键点击工程选择菜单 Git –&amp;gt; Commit Directory…&lt;/p&gt;
&lt;p&gt;（7）右键点击工程选择菜单 Git –&amp;gt; Repository –&amp;gt; Push …&lt;/p&gt;
&lt;p&gt;任务的创建与执行&lt;br&gt;我们以最火的Java项目和Go项目为例，给大家分别演示如何构建项目和执行&lt;/p&gt;
&lt;p&gt;Go项目&lt;/p&gt;
&lt;p&gt;（1）回到首页，点击新建按钮 .如下图，输入名称，选择创建一个自由风格的项目，点击OK&lt;/p&gt;
&lt;p&gt;（2）General管理，可以添加项目描述和GitHub项目路径，以及一些配置&lt;/p&gt;
&lt;p&gt;（3）源码管理，选择GitHub&lt;/p&gt;
&lt;p&gt;（4）构建触发器，配置触发规则，这里以定时和轮询为示例，配别设置为&lt;/p&gt;
&lt;p&gt;定时构建：定时构建1次任务&lt;/p&gt;
&lt;p&gt;轮询SCM:定时查看源码管理的代码是否更新，有更新则构建，否则不会构建&lt;/p&gt;
&lt;p&gt;如图所示，定时构建为每间隔10分钟定时构建一次，轮询SCM为每5分钟轮询检测一次。&lt;/p&gt;
&lt;p&gt;时间*号规则为: 分 时 日 月 周&lt;br&gt;（5）构建环境，配置控制台输出时间戳和指定Go语言版本&lt;/p&gt;
&lt;p&gt;（6）构建，使用Shell脚本测试代码上传后的项目是否有效&lt;/p&gt;
&lt;p&gt;Shell如下:&lt;/p&gt;
&lt;p&gt;export GOPATH=$WORKSPACE/../                    # 指定GOPATH路径，Go语言执行必须有GOPATH路径&lt;br&gt;export GOWORK=$GOPATH/src/github.com/Jenkins    # 创建项目执行时的目录依赖结构&lt;br&gt;cp -rf $WORKSPACE/* $GOWORK/                    # 使测试运行数据和源数据隔离&lt;br&gt;cd $GOWORK &amp;amp;&amp;amp; go build                          # 进入项目目录并执行&lt;br&gt;命令解说：&lt;/p&gt;
&lt;p&gt;$GOPATH Go 运行需要指定 GOPATH 也即项目运行路径&lt;br&gt;$WORKSPACE /var/jenkins_home/workspace/Jenkins&lt;br&gt;GOWORK 创建符合代码依赖的执行目录&lt;br&gt;注:下载Go的插件在构建时，会自动为我们设置GOROOT,但不会指定GOPATH，因此需要指定&lt;br&gt;最后点击“保存”按钮&lt;/p&gt;
&lt;p&gt;（7）执行构建，控制台查看输出&lt;/p&gt;
&lt;p&gt;构建成功，也输出了WORKSPACE、GOPATH、GOROOT目录，说明配置生效。进入docker容器或是挂载目录查看是否有可执行文件：&lt;/p&gt;
&lt;p&gt;除了上述方法，也可以通过shell配置docker等方式构建、部署、运行项目，还可以将项目配置到当前/其他服务器运行，更多配置方式就不一一陈述了，请自行挖掘。&lt;/p&gt;
&lt;p&gt;JAVA项目&lt;/p&gt;
&lt;p&gt;（1）回到首页，点击新建按钮 .如下图，输入名称，选择创建一个Maven项目，点击OK&lt;/p&gt;
&lt;p&gt;（2）源码管理，选择Git&lt;/p&gt;
&lt;p&gt;（3）Build&lt;/p&gt;
&lt;p&gt;命令:&lt;/p&gt;
&lt;p&gt;clean package docker:build -DpushImage&lt;br&gt;用于清除、打包，构建docker镜像&lt;/p&gt;
&lt;p&gt;最后点击“保存”按钮&lt;/p&gt;
&lt;p&gt;（4）执行任务&lt;/p&gt;
&lt;p&gt;后续请参照Go项目的执行步骤。&lt;br&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/PEupc5YIKuctZO1Tivy_ug&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/PEupc5YIKuctZO1Tivy_ug&lt;/a&gt;&lt;/p&gt;

 &lt;ul&gt;
&lt;li&gt;&lt;p&gt;bccomp — 比较两个任意精度的数字&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;bccomp ( string $left_operand , string $right_operand [, int $scale = int ] ) : int&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;参数解释&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;left_operand左边的运算数, 是一个字符串.&lt;/li&gt;
&lt;li&gt;right_operand右边的运算数, 是一个字符串.&lt;/li&gt;
&lt;li&gt;scale可选的scale参数被用作设置指示数字， 在使用来作比较的小数点部分.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;如果两个数相等返回0, 左边的数left_operand比较右边的数right_operand大返回1, 否则返回-1.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;已验证：如果参数是字符串，不论这个字符串是什么，这个字符串始终是0。参数可以为数字作比较。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;bcdiv2个任意精度的数字除法计算&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;bcdiv ( string $left_operand , string $right_operand [, int $scale = int ] ) : string&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;左操作数除以右操作数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;返回结果为字符串类型的结果，如果右操作数是0结果为null&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;已验证：除法结果始终取整，除非指定第三参数.，否则，只保留整数&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;bcmod — 对一个任意精度数字取模&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;bcmod ( string $left_operand , string $modulus ) : string&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;对左操作数使用系数取模&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;返回字符串类型取模后结果，如果系数为0则返回null&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;取模运算实际就是=被除数-除数x(被除数/除数的整数值),例如 100%17 则 100=17&lt;em&gt;5+15 那么100%17=15。这里15就是100-17&lt;/em&gt;5。也就是100%17取模的结果&lt;/p&gt;
&lt;p&gt;已验证：取模的结果始终是一个不包含小数点的数字&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;bcmul — 2个任意精度数字乘法计算&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;bcmul ( string $left_operand , string $right_operand [, int $scale = int ] ) : string&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;左操作数乘以右操作数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;返回结果为字符串类型.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;已验证：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果两个参数的第一位小数点之和大于等于2小于5，则结果值加1。&lt;/li&gt;
&lt;li&gt;如果两个参数的第一位小数点之和大于等于5小于8，则结果值加2。&lt;/li&gt;
&lt;li&gt;如果两个参数的第一位小数点之和大于等于8小于等于10，则结果值加3。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;bcpow — 任意精度数字的乘方&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;bcpow ( string $left_operand , string $right_operand [, int $scale ] ) : string&lt;/li&gt;
&lt;li&gt;左操作数的右操作数次方运算.&lt;/li&gt;
&lt;li&gt;已验证：默认操作不保留小数点，第三参数指定保留小数点位数，才有小数点。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;base_convert — 在任意进制之间转换数字&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;base_convert ( string $number , int $frombase , int $tobase ) : string&lt;ul&gt;
&lt;li&gt;number 要转换的数字&lt;/li&gt;
&lt;li&gt;frombase 当前进制&lt;/li&gt;
&lt;li&gt;tobase 要转换的进制&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;bindec — 二进制转换为十进制&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;decbin ( int $number ) : string&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;decbin — 十进制转换为二进制&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;decbin ( int $number ) : string&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;dechex — 十进制转换为十六进制&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;dechex ( int $number ) : string&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;decoct — 十进制转换为八进制&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;decoct ( int $number ) : string&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;floor — 舍去法取整&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;注意：如果是负数取整的话负数存在小数点且小数点第一位大于等于1的话，结果值加1&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;fmod — 返回除法的浮点数余数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;fmod ( float $x , float $y ) : float&lt;/li&gt;
&lt;li&gt;除法计算返回值的余数，参数可为整数，返回结果始终是浮点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;hexdec — 十六进制转换为十进制&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hexdec ( string $hex_string ) : number&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;intdiv — 对除法结果取整&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;intdiv ( int $dividend , int $divisor ) : int&lt;/li&gt;
&lt;li&gt;dividend 除以 divisor 的商，对该商取整。&lt;/li&gt;
&lt;li&gt;如果 divisor 是 0，将抛出 DivisionByZeroError 异常。 如果 dividend 是 PHP_INT_MIN 并且 divisor 是 -1，将抛出 ArithmeticError 异常.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;is_finite — 判断是否为有限值&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;is_finite ( float $val ) : bool&lt;/li&gt;
&lt;li&gt;如果 val 是本机平台上 PHP 浮点数所允许范围中的一个合法的有限值，则返回 TRUE。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;is_infinite — 判断是否为无限值&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 val 为无穷大返回 TRUE，否则返回 FALSE。、&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;is_nan — 判断是否为合法数值&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;is_nan ( float $val ) : bool&lt;/li&gt;
&lt;li&gt;如果 val 不是一个数字（not a number）返回 TRUE，否则返回 FALSE。&lt;/li&gt;
&lt;li&gt;注：此处我懵逼了，这个函数竟然是—不是数字返回true。是数字返回false&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;lcg_value — 组合线性同余发生器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;lcg_value ( void ) : float&lt;/li&gt;
&lt;li&gt;范围为 (0, 1) 的伪随机数。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;round — 对浮点数进行四舍五入&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;返回将 val 根据指定精度 precision（十进制小数点后数字的数目）进行四舍五入的结果。precision 也可以是负数或零（默认值）。&lt;/li&gt;
&lt;li&gt;round ( float $val [, int $precision = 0 [, int $mode = PHP_ROUND_HALF_UP ]] ) : float&lt;ul&gt;
&lt;li&gt;val要处理的值&lt;/li&gt;
&lt;li&gt;precision可选的十进制小数点后数字的数目。&lt;/li&gt;
&lt;li&gt;mode以下之一： PHP_ROUND_HALF_UP、 PHP_ROUND_HALF_DOWN PHP_ROUND_HALF_EVEN 或 PHP_ROUND_HALF_ODD&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_alnum — 做字母和数字字符检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果text中所有的字符全部是字母和(或者)数字，返回 TRUE 否则返回FALSE&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_alpha — 做纯字符检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果在当前语言环境中 text 里的每个字符都是一个字母，那么就返回TRUE，反之则返回FALSE。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_cntrl — 做控制字符检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;控制字符就是例如：换行、缩进、空格。&lt;/li&gt;
&lt;li&gt;如果在当前的语言环境下 text 里面的每个字符都是控制字符，就返回 TRUE ；反之就返回 FALSE 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_digit — 做纯数字检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 text 字符串是一个十进制数字，就返回 TRUE ；反之就返回 FALSE &lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_graph — 做可打印字符串检测，空格除外&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 text 里面的每个字符都是输出可见的（没有空白），就返回 TRUE ；反之就返回 FALSE 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_lower — 做小写字符检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果在当前的语言环境下 text 里面的每个字符都是小写字母，就返回 TRUE ；反之就返回 FALSE 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_print — 做可打印字符检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果在当前的语言环境下 text 里面的每个字符都能被实际输出（包括空白），就返回 TRUE ；如果 text 里面包含控制字符或者那些根本不会有任何输出的字符串，就返回 FALSE 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_punct — 检测可打印的字符是不是不包含空白、数字和字母&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果在 text 里面的每个字符都是能打印的，但不是字母、数字，也不是空白，那么就返回 TRUE ；反之则返回 FALSE 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_upper — 做大写字母检测&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在当前语言环境下，如果 text 里面的每个字符都是大写字母，就返回 TRUE。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;ctype_xdigit — 检测字符串是否只包含十六进制字符&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 text 里面的每个字符都是十六进制字符。也就是只能包含十进制的树枝和 [A-Fa-f] 的字母。否则，返回 FALSE &lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;filter_has_var — 检测是否存在指定类型的变量&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;typeINPUT_GET、 INPUT_POST、 INPUT_COOKIE、 INPUT_SERVER、 INPUT_ENV 里的其中一个。&lt;/li&gt;
&lt;li&gt;variable_name要检查的变量名。&lt;/li&gt;
&lt;li&gt;成功时返回 TRUE， 或者在失败时返回 FALSE。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;register_shutdown_function — 注册一个会在php中止时执行的函数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;callback待注册的中止回调&lt;/li&gt;
&lt;li&gt;中止回调是作为请求的一部分被执行的，因此可以在它们中进行输出或者读取输出缓冲区。&lt;/li&gt;
&lt;li&gt;parameter  可以通过传入额外的参数来将参数传给中止函数&lt;/li&gt;
&lt;li&gt;可以多次调用 register_shutdown_function() ，这些被注册的回调会按照他们注册时的顺序被依次调用。 如果你在注册的方法内部调用 exit()， 那么所有处理会被中止，并且其他注册的中止回调也不会再被调用。&lt;/li&gt;
&lt;li&gt;如果传入的callback不是可调用的，那么将会产生一个 E_WARNING 级别的错误。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;我下载的是&lt;a href=&#34;https://codeload.github.com/dreamsxin/cphalcon7/tar.gz/Dao7-1.3.3-Stable-0&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;稳定版本&lt;/a&gt; 就是1.3.3-Stable-0版本&lt;br&gt;结果还是编译报错，后来查查资料才知道有坑。&lt;/p&gt;
&lt;p&gt;我的本地gcc版本是gcc version 9.2.1 20190909 (Debian 9.2.1-8)，比较新，所以格式比较严格。作者的版本估计是旧版，所以有点不兼容。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;this ‘for’ clause does not guard… [-Werror=misleading-indentation]&lt;br&gt;158 |                 for (i = 0; i &amp;lt; 1000000; i  );&lt;/p&gt;
&lt;p&gt;这个报错一般是在kernel/time.h的158行，for循环后边冒号去掉，估计作者不太严谨，没去，新版的gcc编译不了。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;xhprof.c:132:19: error: ‘digits’ defined but not used [-Werror=unused-const-variable=]&lt;br&gt;132 | static const char digits[] = “0123456789abcdef”;&lt;br&gt;  这个可以注释掉，新版的gcc编译，定义好的方法声明没有使用，就会报错。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;debug.c:123:24: error: ‘arginfo_phalcon_debug_setcharset’ defined but not used [-Werror=unused-const-variable=]&lt;/p&gt;
&lt;p&gt;  同上，一样的报错。注释掉&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;mvc/model/query.c:190:24: error: ‘arginfo_phalcon_mvc_model_query_setmergebindtypes’ defined but not used [-Werror=unused-const-variable=]&lt;/p&gt;
&lt;p&gt;  还是同上报错。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;adapter/sql.c:75:24: error: ‘arginfo_phalcon_paginator_adapter_sql_setlimit’ defined but not used [-Werror=unused-const-variable=]&lt;/p&gt;
&lt;p&gt;  同上。哎呀，这么多了&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;security.c:166:24: error: ‘arginfo_phalcon_security_pbkdf2’ defined but not used [-Werror=unused-const-variable=]&lt;/p&gt;
&lt;p&gt;  同上。脑壳痛&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;好多地方……报错defined but not used的都去注释掉吧&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;最后附上我自己弄好的一份:&lt;a href=&#34;https://github.com/erikaaron/cphalcon7-1.3.3-Stable-0&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;下载&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;时间：2019-10-03 上午&lt;/p&gt;
&lt;p&gt;早早的起床，光明小镇还是比较偏远的，地铁不通。早早起床赶了一个多小时地铁。刚开始定位的是光明小镇OTC欢乐田园，公交站台是 &lt;strong&gt;第二职业技术学校&lt;/strong&gt;。后来快到站的时候，听到车上有人过去，才知道是&lt;strong&gt;中山七院（或中大附七&lt;/strong&gt;公交站。&lt;br&gt;中大附七附近有停车场，驾车来比较合适。&lt;br&gt;下车，直走车流方向。&lt;br&gt;早上人还是那么多&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;br&gt;&lt;img src=&#34;/img/201910/20191005090513.jpg&#34; alt=&#34;入口&#34;&gt;&lt;/p&gt;
&lt;p&gt;远处的就是观景台&lt;br&gt;&lt;img src=&#34;/img/201910/20191005090521.jpg&#34; alt=&#34;入口&#34;&gt;&lt;/p&gt;
&lt;p&gt;我走了好远的路，反正个人感觉不近。&lt;/p&gt;
&lt;p&gt;进去后，沿着路往里面走。如果想要上观景台（观景台附近的花海不收费）的，可以在售票处买票，大人是20元，小孩是10元。观光小巴的话，大人30元（限乘四次），小孩好像是10元。其实，不建议坐，不如走路观景，就是对于体力不好的有点累。&lt;/p&gt;
&lt;p&gt;观景台吧，个人感觉早上或者傍晚登上看日出或者日落景色比较好，其他时段光线太亮了……&lt;br&gt;&lt;img src=&#34;/img/201910/6574.JPG&#34; alt=&#34;观景台&#34;&gt;&lt;/p&gt;
&lt;p&gt;九月份往后就是向日葵，面积很大，就是没找到太好的拍摄角度&lt;br&gt;&lt;img src=&#34;/img/201910/6543.JPG&#34; alt=&#34;向日葵&#34;&gt;&lt;/p&gt;
&lt;p&gt;观景台下面的小道。&lt;br&gt;&lt;img src=&#34;/img/201910/6560.JPG&#34; alt=&#34;小道&#34;&gt;&lt;/p&gt;
&lt;p&gt;侧面角度&lt;br&gt;&lt;img src=&#34;/img/201910/20191005090446.jpg&#34; alt=&#34;斜坡&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201910/20191005090503.jpg&#34; alt=&#34;斜坡&#34;&gt;&lt;/p&gt;
&lt;p&gt;观景台下的粉黛乱子草&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201910/20191005090540.jpg&#34; alt=&#34;粉黛乱子草&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201910/20191005090549.jpg&#34; alt=&#34;粉黛乱子草&#34;&gt;&lt;/p&gt;
&lt;p&gt;后来我回家特效了一下粉黛乱子草&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201910/20191005090558.jpg&#34; alt=&#34;粉黛乱子草&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201910/20191005090532.jpg&#34; alt=&#34;粉黛乱子草&#34;&gt;&lt;/p&gt;
&lt;p&gt;整体感觉适合带小孩子来休闲，游玩比较放松。就是出入口安排的有点不太好，还有这个地方偏僻，公交车查的不准，最好直接到地铁站。附近也没有的士……&lt;/p&gt;
&lt;p&gt;个人分享攻略：&lt;br&gt;景点：&lt;strong&gt;光明小镇OTC欢乐田园&lt;/strong&gt;，不是光明小镇欢乐田园，两者差距还是很远的，距离也有点远。&lt;br&gt;非驾车的游客到&lt;strong&gt;光晟（sheng）厂&lt;/strong&gt;下车，走&lt;strong&gt;楼村一号路(高德地图是善水路)&lt;/strong&gt; 进去（预计走路十分钟）。逛一圈刚好从2号门出来，从&lt;strong&gt;中山七院（或中大附七）&lt;/strong&gt;坐公交回。&lt;/p&gt;
&lt;p&gt;驾车游客：节假日所有车辆都分流到二号门，&lt;strong&gt;楼村一号路(高德地图是善水路)&lt;/strong&gt; 是不给进的，游玩的话来回就一条路。&lt;/p&gt;

 &lt;p&gt;通用破解永久版本，安装插件即可，支持2019.2版本的大部分ide&lt;/p&gt;
&lt;p&gt;pycharm2019.2  phpstorm2019.2 intelli2019.2 gloand2019.2 clion2019.2 webstorm2019.2&lt;/p&gt;
&lt;p&gt;注意，不要用于商业用途，个人使用练习即可。&lt;/p&gt;
&lt;p&gt;下载平破解插件jetbrainsCrack.jar放到已安装的ide工具目录下的bin目录&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;链接: &lt;a href=&#34;https://pan.baidu.com/s/16KTQF7pOJUhEGnA9EYQbQA&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://pan.baidu.com/s/16KTQF7pOJUhEGnA9EYQbQA&lt;/a&gt;  密码: 3h5e&lt;/p&gt;
&lt;p&gt;在bin目录中编辑&lt;em&gt;.vmoptions和&lt;/em&gt;64.vmoptions文件，引入插件&lt;br&gt;-javaagent:插件地址&lt;/p&gt;
&lt;p&gt;例如我的linux系统格式如下：&lt;br&gt;-javaagent:/opt/phpstorm/bin/jetbrainsCrack.jar&lt;/p&gt;
&lt;p&gt;如果之前有填过激活码就需要删除激活码，还有hosts的地址也删除。&lt;br&gt;linux系统需要直接删除当前用户目录下的已生成ide缓存文件&lt;/p&gt;
&lt;p&gt;启动ide工具后填入下面激活码即可。&lt;/p&gt;
&lt;p&gt;激活一&lt;/p&gt;
&lt;div style=&#34;overflow:scroll&#34;&gt;

&lt;pre&gt;&lt;code&gt;KNBB2QUUR1---&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;
激活二
&lt;div style=&#34;overflow:scroll&#34;&gt;

&lt;pre&gt;&lt;code&gt;3AGXEJXFK9---&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;

&lt;p&gt;激活三&lt;/p&gt;
&lt;div style=&#34;overflow:scroll&#34;&gt;

&lt;pre&gt;&lt;code&gt;A82DEE284F---&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;


&lt;p&gt;以上方法禁止&lt;/p&gt;

 &lt;p&gt;不见蝉鸣，又见初日。&lt;/p&gt;
&lt;p&gt;喧嚣的时间里，起床，赶车，奔跑，填饱肚子……&lt;/p&gt;
&lt;p&gt;连续几天，不能注睡。听着早鸟的声音，突然想起了蝉鸣。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;已是许多年不见蝉鸣了，依稀记得蝉总是一口气连续的扯着嗓子嚎叫。总是吵的午休不能好好，上课不能聚心。忍不住了，跑到树边，一脚踢过去，或者拿起石头拎起来。它一惊，从这棵树窜到那颗树亦或干脆闭嘴……&lt;/p&gt;
&lt;p&gt;惊蝉，蝉已不见踪影。&lt;/p&gt;
&lt;p&gt;时年的日子里，不曾想自己会怀旧。旧的事物：惊蝉，拔草，养兔，偷果子被追……有时还去拽拽老牛的尾巴，它就不屑的扭扭头，帅气的摔着尾巴。生活依旧这样，老牛成了记忆，果子再也不能偷了，兔子早已经不养了，也无蝉可以惊……感叹这样追求的或许成了时代推动的枝叶：要么在一颗树上吊死，要么被树林的枝叶压死。&lt;/p&gt;
&lt;p&gt;终究，落叶亦是一场空，化作沉泥无不同。享受的是过程，根本的结局又有和不同。何尝选择的不就是过程吗，过程中的有一个过程。没有结局的过程，就已经有了结局。完结的结局，不存在完美的结局。是如佛曰，亦成时就。忐忑上把控心灵，气势上早就空目一切。&lt;/p&gt;
&lt;p&gt;我还是我，我又不是我。&lt;/p&gt;
